import{_ as r,o as a,c as o,a1 as d}from"./chunks/framework.BX4nIuL2.js";const g=JSON.parse('{"title":"数字化快速原型与材料工艺卡片库 — CMF 设计美学与规范","description":"","frontmatter":{},"headers":[],"relativePath":"courses/cmf/index.md","filePath":"courses/cmf/index.md"}'),e={name:"courses/cmf/index.md"};function s(n,t,h,l,c,i){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="数字化快速原型与材料工艺卡片库-—-cmf-设计美学与规范" tabindex="-1">数字化快速原型与材料工艺卡片库 — CMF 设计美学与规范 <a class="header-anchor" href="#数字化快速原型与材料工艺卡片库-—-cmf-设计美学与规范" aria-label="Permalink to &quot;数字化快速原型与材料工艺卡片库 — CMF 设计美学与规范&quot;">​</a></h1><blockquote><p><strong>以 ProFabX Prototype 的材料、制造、后处理与数字制造内容为骨架，整理成 CMF 课程可直接使用的工艺选择与样机决策入口。</strong></p></blockquote><hr><h2 id="🏗️-页面架构说明" tabindex="-1">🏗️ 页面架构说明 <a class="header-anchor" href="#🏗️-页面架构说明" aria-label="Permalink to &quot;🏗️ 页面架构说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>技术方案</th><th>描述</th></tr></thead><tbody><tr><td><strong>课程首页</strong></td><td>VitePress Markdown（当前页面）</td><td>提供 CMF 设计定位、材料分类、制造工艺、表面处理与工作流集成等综合索引</td></tr><tr><td><strong>技术细节文档</strong></td><td>VitePress 静态子站点</td><td>点击各章节链接跳转至 Fab 课程对应深度技术文档</td></tr></tbody></table><hr><h2 id="📌-1-cmf-设计定位" tabindex="-1">📌 1. CMF 设计定位 <a class="header-anchor" href="#📌-1-cmf-设计定位" aria-label="Permalink to &quot;📌 1. CMF 设计定位&quot;">​</a></h2><p><strong>时代之变（Why）：</strong> 在数字化制造时代，原型的外观（Color）、质感（Material）与工艺（Finishing）已不再是产品开发链末端的装饰环节，而是从概念阶段就应当深度介入的工程决策维度。一个优秀的 CMF 设计，能将功能结构、用户体验与制造经济性统一在同一视觉语言之下。</p><p><strong>方法之新（How）：</strong> 本卡片库以 ProFabX Prototype 的知识体系为骨架，将常见的原型制造材料、增材/减材工艺、表面处理方法与工作流规范整理为标准化的知识卡片。通过 <strong>&quot;材料—工艺—后处理&quot;</strong> 的三层分类体系，帮助学习者在面对具体原型需求时，能够快速做出最优的工艺链决策。</p><p><strong>成果之硬（What）：</strong> CMF 卡片库覆盖 <strong>13 张核心知识卡片</strong>，横跨 <strong>6 大工艺域</strong>（材料、增材、减材、成型、表面、工作流），每张卡片均包含材料选型、执行路径、输出目标及外部参考链接。</p><h3 id="_1-1-核心能力培养" tabindex="-1">1.1 核心能力培养 <a class="header-anchor" href="#_1-1-核心能力培养" aria-label="Permalink to &quot;1.1 核心能力培养&quot;">​</a></h3><p>通过 CMF 卡片库的学习与实践，培养以下核心能力：</p><ul><li><strong>材料选择决策</strong>：在工程塑料、金属、复合材料之间，根据刚性/韧性/耐温/成本做出科学取舍。</li><li><strong>工艺链规划</strong>：理解从设计文件到物理原型的最优路径，平衡精度、速度与成本。</li><li><strong>表面处理把控</strong>：掌握从喷砂拉丝到功能涂层的质感控制参数。</li><li><strong>制造经济性判断</strong>：建立单件原型与小批量生产之间的成本意识。</li><li><strong>跨学科整合</strong>：将 CMF 决策与结构设计、电子功能、用户体验统一考虑。</li></ul><hr><h2 id="🎯-1-2-适用对象" tabindex="-1">🎯 1.2 适用对象 <a class="header-anchor" href="#🎯-1-2-适用对象" aria-label="Permalink to &quot;🎯 1.2 适用对象&quot;">​</a></h2><ul><li><strong>产品设计学生</strong>：希望在原型开发中系统掌握材料与工艺选择逻辑。</li><li><strong>Fab Lab 学习者</strong>：在进行数字化制造项目时需要 CMF 决策参考。</li><li><strong>创客与工程师</strong>：希望建立从原型到量产的 CMF 知识框架。</li></ul><hr><h2 id="🧱-2-材料分类" tabindex="-1">🧱 2. 材料分类 <a class="header-anchor" href="#🧱-2-材料分类" aria-label="Permalink to &quot;🧱 2. 材料分类&quot;">​</a></h2><h3 id="_2-1-工程塑料族" tabindex="-1">2.1 工程塑料族 <a class="header-anchor" href="#_2-1-工程塑料族" aria-label="Permalink to &quot;2.1 工程塑料族&quot;">​</a></h3><p>从外观壳体到耐磨功能件，建立课程中最常用的塑料材料选择逻辑。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>代表材料</strong></td><td>ABS、PC、POM、PEEK、TPU、尼龙</td></tr><tr><td><strong>关键词</strong></td><td>塑料基材、强度/韧性、触感</td></tr><tr><td><strong>执行路径</strong></td><td>按刚性、韧性、耐温和耐磨建立材料表 → 区分展示件、结构件和运动件需求 → 选择匹配的打印、CNC 或注塑路径 → 记录材料成本、可得性和表面处理兼容性</td></tr><tr><td><strong>输出目标</strong></td><td>让学生先判断材料角色，再选择制造工艺</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/polymers/peek/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/0manage/material.html">本地课程文档</a></td></tr></tbody></table><h3 id="_2-2-金属材料族" tabindex="-1">2.2 金属材料族 <a class="header-anchor" href="#_2-2-金属材料族" aria-label="Permalink to &quot;2.2 金属材料族&quot;">​</a></h3><p>围绕铝、铜、钛、不锈钢等金属基材，理解重量、强度、导热、导电和表面处理之间的取舍。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>代表材料</strong></td><td>铝合金、铜合金、钛合金、不锈钢</td></tr><tr><td><strong>关键词</strong></td><td>铝合金、铜合金、钛合金</td></tr><tr><td><strong>执行路径</strong></td><td>按重量、强度、散热和成本建立选择标准 → 匹配 CNC、钣金、SLM 或铸造路径 → 预留阳极、拉丝、喷砂或电镀余量 → 用真实样板比对颜色、反光和触感</td></tr><tr><td><strong>输出目标</strong></td><td>把金属 CMF 训练落实到结构和制造约束</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/metal/al/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/8CNC_manufacture/cnctype.html">本地课程文档</a></td></tr></tbody></table><h3 id="_2-3-纤维增强复合材料" tabindex="-1">2.3 纤维增强复合材料 <a class="header-anchor" href="#_2-3-纤维增强复合材料" aria-label="Permalink to &quot;2.3 纤维增强复合材料&quot;">​</a></h3><p>以 PA-CF、PA-GF、ABS-GF 等复合材料建立轻量化原型中的强度方向、层纹、磨耗和加工风险判断。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>代表材料</strong></td><td>PA-CF、PA-GF、ABS-GF、碳纤维纹理</td></tr><tr><td><strong>关键词</strong></td><td>PA-CF、PA-GF、轻量化</td></tr><tr><td><strong>执行路径</strong></td><td>识别主受力方向与各向异性风险 → 选择连续纤维、短纤维或粉末烧结路径 → 处理喷嘴磨耗、收缩和表面粗糙度 → 通过夹具或实测验证刚度收益</td></tr><tr><td><strong>输出目标</strong></td><td>让复合材料不只停留在外观纹理，而成为结构决策工具</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/componsites/pacf/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/0manage/material.html">本地课程文档</a></td></tr></tbody></table><hr><h2 id="🖨️-3-增材制造工艺" tabindex="-1">🖨️ 3. 增材制造工艺 <a class="header-anchor" href="#🖨️-3-增材制造工艺" aria-label="Permalink to &quot;🖨️ 3. 增材制造工艺&quot;">​</a></h2><h3 id="_3-1-fdm-熔融沉积" tabindex="-1">3.1 FDM 熔融沉积 <a class="header-anchor" href="#_3-1-fdm-熔融沉积" aria-label="Permalink to &quot;3.1 FDM 熔融沉积&quot;">​</a></h3><p>适合课程早期体量、装配、握持和机构干涉验证。重点在层纹方向、支撑策略、壁厚和嵌件预留。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>PLA、ABS、ASA、TPU、PA-CF</td></tr><tr><td><strong>关键词</strong></td><td>结构草模、低成本、装配验证</td></tr><tr><td><strong>执行路径</strong></td><td>按受力方向确定打印姿态 → 预留螺母、热熔铜柱与走线槽 → 用 0.2mm 层高完成首版验证 → 对关键面进行打磨、补土或喷漆</td></tr><tr><td><strong>输出目标</strong></td><td>快速得到可握持、可装配、可测试的第一轮样机</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/polymers/asa/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/3_3dprinter/2.FDM3Dprintingbackground.html">本地课程文档</a></td></tr></tbody></table><h3 id="_3-2-lcd-dlp-光固化" tabindex="-1">3.2 LCD / DLP 光固化 <a class="header-anchor" href="#_3-2-lcd-dlp-光固化" aria-label="Permalink to &quot;3.2 LCD / DLP 光固化&quot;">​</a></h3><p>适合高精度外观件、小型结构、透明罩、CMF 质感样板。重点训练支撑痕迹、清洗固化和表面处理。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>标准树脂、透明树脂、韧性树脂</td></tr><tr><td><strong>关键词</strong></td><td>精细表面、透明树脂、视觉样件</td></tr><tr><td><strong>执行路径</strong></td><td>拆分可见面与支撑面 → 设置排液孔和空腔壁厚 → 清洗、二次固化并修整支撑痕迹 → 通过喷涂或抛光形成最终质感</td></tr><tr><td><strong>输出目标</strong></td><td>让设计意图在比例、边缘和表面细节上被准确表达</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/manufacture/add/lcddlp/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/3_3dprinter/5.SLAbackground.html">本地课程文档</a></td></tr></tbody></table><h3 id="_3-3-sls-mjf-尼龙烧结" tabindex="-1">3.3 SLS / MJF 尼龙烧结 <a class="header-anchor" href="#_3-3-sls-mjf-尼龙烧结" aria-label="Permalink to &quot;3.3 SLS / MJF 尼龙烧结&quot;">​</a></h3><p>适合卡扣、铰链、轻量化壳体和耐冲击结构。用它连接外观样机与功能样机。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>PA12、PA11、TPU、PA-CF</td></tr><tr><td><strong>关键词</strong></td><td>功能样机、尼龙、小批量</td></tr><tr><td><strong>执行路径</strong></td><td>按功能面定义关键公差 → 为粉末清理预留孔位与开口 → 验证卡扣、铰链、耐冲击结构 → 染色、喷砂或浸渗提升外观一致性</td></tr><tr><td><strong>输出目标</strong></td><td>把 CMF 样件推进到接近真实使用场景的功能验证</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/polymers/pa/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/3_3dprinter/7.hpmjf.html">本地课程文档</a></td></tr></tbody></table><hr><h2 id="🔩-4-减材制造工艺" tabindex="-1">🔩 4. 减材制造工艺 <a class="header-anchor" href="#🔩-4-减材制造工艺" aria-label="Permalink to &quot;🔩 4. 减材制造工艺&quot;">​</a></h2><h3 id="_4-1-cnc-精密加工" tabindex="-1">4.1 CNC 精密加工 <a class="header-anchor" href="#_4-1-cnc-精密加工" aria-label="Permalink to &quot;4.1 CNC 精密加工&quot;">​</a></h3><p>适合铝合金外壳、旋钮、支架、散热件和高精度装配面。关注刀路可达性、倒角、纹理方向和后处理余量。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>铝合金、铜合金、钛合金、POM、亚克力</td></tr><tr><td><strong>关键词</strong></td><td>铝合金、高精度、真实材质</td></tr><tr><td><strong>执行路径</strong></td><td>把外观面和基准面分离管理 → 约束内角半径和刀具可达性 → 预留阳极、喷砂或抛光余量 → 用装配件复核孔位和配合公差</td></tr><tr><td><strong>输出目标</strong></td><td>建立学生对真实材料、加工限制与工业质感之间关系的判断力</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/en/prototype/manufacture/substractive/cnc/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/8CNC_manufacture/cnctype.html">本地课程文档</a></td></tr></tbody></table><hr><h2 id="⚙️-5-成型工艺" tabindex="-1">⚙️ 5. 成型工艺 <a class="header-anchor" href="#⚙️-5-成型工艺" aria-label="Permalink to &quot;⚙️ 5. 成型工艺&quot;">​</a></h2><h3 id="_5-1-钣金折弯" tabindex="-1">5.1 钣金折弯 <a class="header-anchor" href="#_5-1-钣金折弯" aria-label="Permalink to &quot;5.1 钣金折弯&quot;">​</a></h3><p>适合底盘、支架、防护罩、电控盒和课程机器人框架。关键是折弯半径、展开图、孔边距和表面喷涂策略。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>冷轧板、镀锌板、铝板、不锈钢</td></tr><tr><td><strong>关键词</strong></td><td>支架、外壳、展开图</td></tr><tr><td><strong>执行路径</strong></td><td>用折弯线定义结构逻辑 → 检查孔边距和干涉风险 → 输出展开图与折弯顺序 → 结合喷粉、拉丝或阳极完成 CMF</td></tr><tr><td><strong>输出目标</strong></td><td>让原型从塑料打印件升级为更接近工业装配的结构件</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/metal/al/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/2cad/fusion360-sheetmetal.html">本地课程文档</a></td></tr></tbody></table><h3 id="_5-2-注塑与硅胶覆膜" tabindex="-1">5.2 注塑与硅胶覆膜 <a class="header-anchor" href="#_5-2-注塑与硅胶覆膜" aria-label="Permalink to &quot;5.2 注塑与硅胶覆膜&quot;">​</a></h3><p>适合讲解拔模、分型线、缩水、嵌件与软胶包覆。课程不只做样机，还要理解未来量产中的设计取舍。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>ABS、PC、PP、TPU、硅胶、PU</td></tr><tr><td><strong>关键词</strong></td><td>量产判断、拔模、软硬复合</td></tr><tr><td><strong>执行路径</strong></td><td>标注拔模方向与分型线 → 检查壁厚、筋位和缩水风险 → 用软胶区域定义触感与防滑性能 → 建立样机成本与模具成本对照</td></tr><tr><td><strong>输出目标</strong></td><td>把 CMF 从视觉选择推进到结构、触感和制造经济性的综合决策</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/material/polymers/tpu/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/9MOLD/mold.html">本地课程文档</a></td></tr></tbody></table><hr><h2 id="🎨-6-表面处理" tabindex="-1">🎨 6. 表面处理 <a class="header-anchor" href="#🎨-6-表面处理" aria-label="Permalink to &quot;🎨 6. 表面处理&quot;">​</a></h2><h3 id="_6-1-喷砂、抛光与拉丝" tabindex="-1">6.1 喷砂、抛光与拉丝 <a class="header-anchor" href="#_6-1-喷砂、抛光与拉丝" aria-label="Permalink to &quot;6.1 喷砂、抛光与拉丝&quot;">​</a></h3><p>统一管理表面粗糙度、反光、边缘倒角和触感。适合建立 CMF 样板册，让同一造型呈现多种质感。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>铝合金、不锈钢、树脂、亚克力</td></tr><tr><td><strong>关键词</strong></td><td>质感控制、样板册、边缘处理</td></tr><tr><td><strong>执行路径</strong></td><td>记录基材、砂号、压力和处理时长 → 控制可见边的倒角一致性 → 对比哑光、半哑光与镜面效果 → 将样板编号并归档到课程材料库</td></tr><tr><td><strong>输出目标</strong></td><td>让学生能用参数描述质感，而不是只说&quot;高级&quot;或&quot;好看&quot;</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/postprocess/postprocess/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/3_3dprinter/8.postprocess.html">本地课程文档</a></td></tr></tbody></table><h3 id="_6-2-导电与功能涂层" tabindex="-1">6.2 导电与功能涂层 <a class="header-anchor" href="#_6-2-导电与功能涂层" aria-label="Permalink to &quot;6.2 导电与功能涂层&quot;">​</a></h3><p>适合把外观件、电磁屏蔽、触摸电极和结构件连接起来。可作为材料、电子和产品体验的跨学科案例。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>导电漆、铜箔、树脂件、塑料壳体</td></tr><tr><td><strong>关键词</strong></td><td>功能表面、触摸电极、屏蔽</td></tr><tr><td><strong>执行路径</strong></td><td>区分装饰层与功能层 → 规划接地、触摸或屏蔽路径 → 用遮蔽和分区控制涂层边界 → 完成导通、附着力和耐磨测试</td></tr><tr><td><strong>输出目标</strong></td><td>把 CMF 训练从外观审美扩展到功能材料应用</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/postprocess/functional/conductive/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/4electric_design/basicknowledge.html">本地课程文档</a></td></tr></tbody></table><hr><h2 id="🔄-7-工作流集成" tabindex="-1">🔄 7. 工作流集成 <a class="header-anchor" href="#🔄-7-工作流集成" aria-label="Permalink to &quot;🔄 7. 工作流集成&quot;">​</a></h2><h3 id="_7-1-数字沙盘原型" tabindex="-1">7.1 数字沙盘原型 <a class="header-anchor" href="#_7-1-数字沙盘原型" aria-label="Permalink to &quot;7.1 数字沙盘原型&quot;">​</a></h3><p>面向课程展示、展厅模型和产品路演的综合原型路径，强调模型比例、模块拆分、灯光/交互与可维护结构。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>亚克力、树脂、铝型材、灯带</td></tr><tr><td><strong>关键词</strong></td><td>展示模型、结构拆分、交互陈列</td></tr><tr><td><strong>执行路径</strong></td><td>定义展示场景与观察距离 → 拆分外壳、底座、灯光与控制模块 → 建立比例模型并完成装配校验 → 输出维护清单与展示说明</td></tr><tr><td><strong>输出目标</strong></td><td>形成可巡展的高完成度原型，而不是单次拍摄用样机</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/sandtable/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/doc/1projectmanage/Assessment1.html">本地课程文档</a></td></tr></tbody></table><h3 id="_7-2-探索数字制造" tabindex="-1">7.2 探索数字制造 <a class="header-anchor" href="#_7-2-探索数字制造" aria-label="Permalink to &quot;7.2 探索数字制造&quot;">​</a></h3><p>将 CAD、材料选择、工艺约束、后处理与复盘文档串联成一个可重复的课程流程，适合 CMF 小组项目管理。</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>适用材料</strong></td><td>PLA、ABS、亚克力、木材</td></tr><tr><td><strong>关键词</strong></td><td>FabLab、课程流程、复盘文档</td></tr><tr><td><strong>执行路径</strong></td><td>建立需求与造型边界 → 选择低风险快速工艺完成第一版 → 通过 CMF 样板校正颜色、质感与结构 → 沉淀 BOM、工艺参数与失败样本</td></tr><tr><td><strong>输出目标</strong></td><td>让学生把工具使用转化成可迁移的工程决策能力</td></tr><tr><td><strong>参考文档</strong></td><td><a href="https://profabx.com/prototype/exploredigitalfabrication/" target="_blank" rel="noreferrer">ProFabX 源页面</a> · <a href="/docs/courses/fab-course/">本地课程文档</a></td></tr></tbody></table><hr><h2 id="📚-技术文档章节" tabindex="-1">📚 技术文档章节 <a class="header-anchor" href="#📚-技术文档章节" aria-label="Permalink to &quot;📚 技术文档章节&quot;">​</a></h2><p>以上 CMF 知识卡片的内容深度依托 Fab 课程的技术文档体系。点以下链接查看详细实验指南与参考材料：</p><ul><li><a href="/docs/courses/fab-course/doc/0manage/material.html">工程塑料与材料选择指南</a></li><li><a href="/docs/courses/fab-course/doc/3_3dprinter/3.FDM-designguide.html">FDM 3D 打印设计指南</a></li><li><a href="/docs/courses/fab-course/doc/8CNC_manufacture/cnctype.html">CNC 数控加工工艺文档</a></li><li><a href="/docs/courses/fab-course/doc/2cad/fusion360-sheetmetal.html">钣金设计指南</a></li><li><a href="/docs/courses/fab-course/doc/9MOLD/mold.html">翻模与铸造工艺文档</a></li><li><a href="/docs/courses/fab-course/doc/3_3dprinter/8.postprocess.html">后处理与表面工艺文档</a></li></ul><hr><h2 id="💬-划词批注互动区" tabindex="-1">💬 划词批注互动区 <a class="header-anchor" href="#💬-划词批注互动区" aria-label="Permalink to &quot;💬 划词批注互动区&quot;">​</a></h2><p>本平台已集成<strong>高保真本地划词评论系统</strong>。如果您对材料选择、工艺路径或 CMF 设计方案存在任何疑问：</p><ol><li>请先在<a href="/docs/">主站首页</a>注册并登录。</li><li>返回本页面，<strong>用鼠标直接划选目标文字</strong>，即可触发高亮批注面板进行提问或讨论。</li><li>您的疑问将会显示在对应文本行下，助您与社区极客共同进步！</li></ol>',75)])])}const p=r(e,[["render",s]]);export{g as __pageData,p as default};
